QueryScript.Source:
 import sailpoint.object.QueryOptions;
 import sailpoint.object.Filter;
 import sailpoint.object.IdentityRequest;
 import sailpoint.object.Identity;
 import java.util.Calendar;
 import java.util.Date;
 import org.apache.commons.logging.Log;
 import org.apache.log4j.Logger;
 import org.apache.log4j.Level;



 List requestTypes = new ArrayList();
// requestTypes.add("WBLeaver");
// requestTypes.add("IFCLeaver");

 requestTypes.add("Lifecycle");
 requestTypes.add("AccessRequest");

 Calendar calendar = Calendar.getInstance();
 calendar.set(Calendar.HOUR_OF_DAY, 0);
 calendar.set(Calendar.HOUR_OF_DAY, 0);
 calendar.set(Calendar.MINUTE, 0);
 calendar.set(Calendar.SECOND, 0);
 calendar.set(Calendar.MILLISECOND, 0);

 calendar.set(Calendar.DAY_OF_WEEK, Calendar.SUNDAY);
 long lastSundayEpoch = calendar.getTimeInMillis();
 Date lastSundayDate = new Date(lastSundayEpoch);
 calendar.add(Calendar.WEEK_OF_YEAR, -10);
 long previousLastSundayEpoch = calendar.getTimeInMillis();
 Date previousLastSundayDate = new Date(previousLastSundayEpoch);

 Filter LeaverFilters = Filter.and(Filter.in("type" ,requestTypes) ,Filter.and( Filter.ge("created",previousLastSundayDate) ,Filter.le("created",lastSundayDate)),Filter.subquery("targetId", Identity.class, "id", Filter.ignoreCase(Filter.eq("correlated", false))));
 QueryOptions qo = new QueryOptions();
 qo.add(LeaverFilters);
 return qo;

