 import sailpoint.object.Identity;
 import sailpoint.api.SailPointContext;
 import sailpoint.object.Application;
 import sailpoint.api.IdentityService;
 import sailpoint.object.Link;
 import org.apache.commons.logging.Log;
 import org.apache.log4j.Logger;
 import org.apache.log4j.Level;
 Logger log = Logger.getLogger("LeaverReport-StatusReport");

 log.debug(value+" inside First Name= "+value);
 String firstName= null;
 if(null != value)
 {

 Identity id = context.getObjectById(Identity.class, value);
 if(null != id)
 {
 firstName = id.getAttribute("firstname");
 log.debug(value+" First Name= "+firstName);

 if(null == firstName)
 {
  Application appObject = context.getObjectByName(Application.class, "ActiveDirectory");
// Application appObject = context.getObjectByName(Application.class, "CDIR_Common-Directory");
 if(null != appObject)
 {

 IdentityService is = new IdentityService(context);	
 List cidrCommAccounts = is.getLinks(id,appObject);
 if (null != cidrCommAccounts)
 {
 for (Link cdirLink : cidrCommAccounts)
 {
 firstName =(String)cdirLink.getAttribute("givenName");
 //firstName =(String)cdirLink.getAttribute("FIRST_NAME");
 log.debug(value+" insideFor= "+firstName);
 }
 }

 }


 }
 }
 }
 log.debug(value+" FinalFirst Name= "+firstName);
 return firstName;

